const items = $input.all();
const results = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const bin = item.binary?.data;

  if (!bin) {
    results.push({ json: { error: 'No image' } });
    continue;
  }

  // Get actual binary buffer using n8n helper
  const buffer = await this.helpers.getBinaryDataBuffer(i, 'data');
  const base64Data = buffer.toString('base64');

  // Check for caption from Telegram message
  const caption = item.json.message?.caption || '';
  const captionContext = caption ? `\n\nUser provided context: "${caption}"` : '';

  const body = {
    model: 'claude-sonnet-4-20250514',
    max_tokens: 1024,
    messages: [{
      role: 'user',
      content: [
        { type: 'image', source: { type: 'base64', media_type: bin.mimeType || 'image/jpeg', data: base64Data } },
        { type: 'text', text: `Analyze this receipt image. Return ONLY valid JSON with these fields:
- vendor (string): Store/business name
- amount (number): Total amount
- date (string): YYYY-MM-DD format
- category (string): One of these EXACT values: "Infrastructure", "Marketing", "Software & Subscriptions", "Professional Development", "Meals & Entertainment", "Travel & Mileage", "Office Supplies", "Legal & Professional Fees", "Other"
- description (string): Brief 2-5 word description
- confidence (string): high/medium/low
- is_personal (boolean): true if personal expense, false if business

Category guidance:
- Infrastructure: domains, hosting, servers, Cloudflare, AWS
- Marketing: business cards, ads, networking events
- Software & Subscriptions: SaaS tools, licenses, subscriptions
- Professional Development: certs, courses, training, tuition
- Meals & Entertainment: restaurants, food, dining
- Travel & Mileage: uber, lyft, flights, hotels, gas
- Office Supplies: supplies, equipment, Amazon office items
- Legal & Professional Fees: lawyers, accountants, CPAs
- Other: anything that doesn't fit above${captionContext}` }
      ]
    }]
  };
  results.push({ json: { requestBody: JSON.stringify(body), chatId: item.json.message?.chat?.id, caption: caption } });
}

return results;

const items = $input.all();
const results = [];
for (const item of items) {
  let text = item.json.content?.[0]?.text || '';
  try {
    text = text.replace(/```json\n?|\n?```/g, '').trim();
    const parsed = JSON.parse(text);
    parsed.amount = parseFloat(parsed.amount) || 0;
    if (!parsed.vendor || !parsed.amount) parsed.confidence = 'low';
    results.push({ json: parsed });
  } catch (e) {
    results.push({ json: { error: 'Parse failed', raw: text, confidence: 'low' } });
  }
}
return results;

const items = $input.all();
return items.map(item => {
  const d = item.json;
  let account = 'Relay - Operating';
  if (d.category && d.category.toLowerCase().includes('software')) account = 'Relay - Tools SaaS';
  if (d.is_personal === true) account = 'Personal - John';
  return { json: { ...d, sourceAccount: account } };
});

const item = $input.first();
const d = item.json;

// Map Firefly III category to folder name (matching actual Nextcloud folders)
function getCategoryFolder(category) {
  const cat = (category || '').toLowerCase();

  if (cat.includes('infrastructure')) return 'Domains';
  if (cat.includes('marketing')) return 'Marketing';
  if (cat.includes('software') || cat.includes('subscription')) return 'Software';
  if (cat.includes('professional development')) return 'Formation';
  if (cat.includes('meals') || cat.includes('entertainment')) return 'Meals';
  if (cat.includes('travel') || cat.includes('mileage')) return 'Travel';
  if (cat.includes('office')) return 'Office';
  if (cat.includes('legal') || cat.includes('professional fees')) return 'Professional_Services';
  return 'Other';
}

const categoryFolder = getCategoryFolder(d.category);

// Build file path
const date = d.date;
const cleanVendor = d.vendor.replace(/[^a-zA-Z0-9]/g, '_').substring(0, 30);
const amount = String(d.amount).replace('.', '_');
const fileName = `${date}_${cleanVendor}_${amount}.jpg`;
const folderPath = `/CODISTECH/Business/Business Vault/09_Receipts_&_Expenses/${categoryFolder}`;
const fullPath = `${folderPath}/${fileName}`;

// Get the base64 image data from Convert to Base64 node
const convertNode = $('Convert to Base64').first();
const requestBody = JSON.parse(convertNode.json.requestBody);
const imageBase64 = requestBody.messages[0].content[0].source.data;

// Convert base64 to binary data for upload
const imageBuffer = Buffer.from(imageBase64, 'base64');
const binaryData = await this.helpers.prepareBinaryData(imageBuffer, fileName, 'image/jpeg');

return [{
  json: {
    ...d,
    nextcloudPath: fullPath,
    nextcloudFolder: folderPath,
    categoryFolder: categoryFolder,
    fileName: fileName
  },
  binary: {
    data: binaryData
  }
}];
